package dev.yazidcv.candidate;
import dev.yazidcv.application.CandidateApplicationRepository;import dev.yazidcv.cv.CvDocumentRepository;import dev.yazidcv.review.ReviewRepository;import org.springframework.beans.factory.annotation.Value;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.io.IOException;import java.nio.file.*;import java.util.*;
@Service public class CandidateErasureService{
 private final CandidateRepository candidates;private final CandidateApplicationRepository applications;private final ReviewRepository reviews;private final CvDocumentRepository documents;private final Path root;
 public CandidateErasureService(CandidateRepository c,CandidateApplicationRepository a,ReviewRepository r,CvDocumentRepository d,@Value("${yazidcv.upload-directory}")String root){candidates=c;applications=a;reviews=r;documents=d;this.root=Paths.get(root).toAbsolutePath().normalize();}
 @Transactional(rollbackFor=IOException.class) public void erase(UUID org,UUID id)throws IOException{var candidate=candidates.findByIdAndOrganizationId(id,org).orElseThrow(()->new NoSuchElementException("Candidate not found"));var cvs=documents.findAllByOrganizationIdAndCandidateId(org,id);applications.deleteAll(applications.findAllByOrganizationIdAndCandidateId(org,id));reviews.deleteAll(reviews.findAllByOrganizationIdAndCandidateId(org,id));documents.deleteAll(cvs);candidates.delete(candidate);for(var cv:cvs){Path file=root.resolve(cv.getStorageKey()).normalize();if(file.startsWith(root))Files.deleteIfExists(file);}}
}
